using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace Warehouse.Tests;

[TestClass]
public class InventoryTrackerTests
{
    private InventoryTracker _tracker = null!;

    [TestInitialize]
    public void Setup()
    {
        _tracker = new InventoryTracker();
    }

    #region GetStockLevel Tests

    [TestMethod]
    public void GetStockLevel_UnknownSku_ReturnsZero()
    {
        var level = _tracker.GetStockLevel("UNKNOWN-SKU");

        Assert.AreEqual(0, level);
    }

    [TestMethod]
    public void GetStockLevel_AfterAddingStock_ReturnsCorrectQuantity()
    {
        _tracker.AddStock("SKU-001", 50);

        var level = _tracker.GetStockLevel("SKU-001");

        Assert.AreEqual(50, level);
    }

    [TestMethod]
    public void GetStockLevel_AfterMultipleAdds_ReturnsCumulativeQuantity()
    {
        _tracker.AddStock("SKU-001", 30);
        _tracker.AddStock("SKU-001", 20);

        var level = _tracker.GetStockLevel("SKU-001");

        Assert.AreEqual(50, level);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void GetStockLevel_NullSku_ThrowsArgumentException()
    {
        _tracker.GetStockLevel(null!);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void GetStockLevel_EmptySku_ThrowsArgumentException()
    {
        _tracker.GetStockLevel(string.Empty);
    }

    #endregion

    #region AddStock Tests

    [TestMethod]
    public void AddStock_ValidSkuAndQuantity_IncreasesStockLevel()
    {
        _tracker.AddStock("SKU-100", 25);

        Assert.AreEqual(25, _tracker.GetStockLevel("SKU-100"));
    }

    [TestMethod]
    public void AddStock_CalledMultipleTimes_AccumulatesStock()
    {
        _tracker.AddStock("SKU-100", 10);
        _tracker.AddStock("SKU-100", 15);
        _tracker.AddStock("SKU-100", 5);

        Assert.AreEqual(30, _tracker.GetStockLevel("SKU-100"));
    }

    [TestMethod]
    public void AddStock_DifferentSkus_TrackedIndependently()
    {
        _tracker.AddStock("SKU-A", 10);
        _tracker.AddStock("SKU-B", 20);

        Assert.AreEqual(10, _tracker.GetStockLevel("SKU-A"));
        Assert.AreEqual(20, _tracker.GetStockLevel("SKU-B"));
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void AddStock_NullSku_ThrowsArgumentException()
    {
        _tracker.AddStock(null!, 10);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void AddStock_EmptySku_ThrowsArgumentException()
    {
        _tracker.AddStock("", 10);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentOutOfRangeException))]
    public void AddStock_ZeroQuantity_ThrowsArgumentOutOfRangeException()
    {
        _tracker.AddStock("SKU-001", 0);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentOutOfRangeException))]
    public void AddStock_NegativeQuantity_ThrowsArgumentOutOfRangeException()
    {
        _tracker.AddStock("SKU-001", -5);
    }

    #endregion

    #region NeedsReorder Tests

    [TestMethod]
    public void NeedsReorder_StockAtZero_ReturnsTrue()
    {
        var result = _tracker.NeedsReorder("SKU-EMPTY");

        Assert.IsTrue(result);
    }

    [TestMethod]
    public void NeedsReorder_StockBelowThreshold_ReturnsTrue()
    {
        _tracker.AddStock("SKU-LOW", 5);

        var result = _tracker.NeedsReorder("SKU-LOW");

        Assert.IsTrue(result);
    }

    [TestMethod]
    public void NeedsReorder_StockAboveThreshold_ReturnsFalse()
    {
        _tracker.AddStock("SKU-HIGH", 100);

        var result = _tracker.NeedsReorder("SKU-HIGH");

        Assert.IsFalse(result);
    }

    [TestMethod]
    [ExpectedException(typeof(ArgumentException))]
    public void NeedsReorder_NullSku_ThrowsArgumentException()
    {
        _tracker.NeedsReorder(null!);
    }

    #endregion
}

